  "0:0":"AHU1.SupplyAirTemp","0:1":"AHU1.ReturnAirTemp","0:2":"Chiller1.ChWSupplyTemp","0:3":"Zone1.Humidity","0:4":"Building.TotalPower",
  "1:0":"AHU1.SupplyFanSpeed","1:1":"AHU1.CoolingValve","1:2":"AHU1.HeatingValve","1:3":"VAV1.DamperPosition","1:4":"Pump1.SpeedCommand",
  "2:0":"AHU1.SupplyAirTempSetpoint","2:1":"Zone1.TempSetpoint","2:2":"Zone2.TempSetpoint","2:3":"Chiller1.ChWSetpoint","2:4":"Building.DemandLimit",
  "3:0":"AHU1.SupplyFanStatus","3:1":"AHU1.FilterStatus","3:2":"Chiller1.RunStatus","3:3":"Pump1.RunStatus","3:4":"FireAlarm.Status",
  "4:0":"AHU1.SupplyFanCommand","4:1":"Chiller1.EnableCommand","4:2":"Pump1.StartCommand","4:3":"Lighting.Zone1Command","4:4":"Lighting.Zone2Command",
  "5:0":"System.OccupiedMode","5:1":"AHU1.Enable","5:2":"NightSetback.Active","5:3":"Holiday.Mode","5:4":"Alarm.GlobalEnable",
  "13:0":"AHU1.UnitStatus","13:1":"Chiller1.Mode","13:2":"System.Season","13:3":"Zone1.FanSpeed","13:4":"Generator.Status",
  "14:0":"AHU1.FanSpeedCommand","14:1":"Damper.PositionCmd","14:2":"Boiler.StageCommand","14:3":"Lighting.SceneCmd","14:4":"Pump.SpeedCommand",
  "19:0":"System.OperatingMode","19:1":"AHU1.FanMode","19:2":"Zone1.HVACMode","19:3":"Lighting.Scene","19:4":"Chiller.Sequence",
  "40:0":"Building.Name","40:1":"AHU1.Location","40:2":"System.FirmwareTag","40:3":"Maintenance.Note","40:4":"Operator.Message"
};
const TN={0:"AI",1:"AO",2:"AV",3:"BI",4:"BO",5:"BV",13:"MSI",14:"MO",19:"MSV",40:"CSV"};
const buf={AI:{},AO:{},AV:{},BI:{},BO:{},BV:{},MSI:{},MO:{},MSV:{},CSV:{}};
try{
  const items = msg.payload.values || msg.payload || [];
  for(const it of items){
    const t=it.objectId.type, k=t+":"+it.objectId.instance, nm=MAP[k]||k;
    let v=null;
    try{ v=it.values[0].value[0].value; if((t===0||t===1||t===2)&&typeof v==="number") v=parseFloat(v.toFixed(1)); }catch(e){}
    const tn=TN[t]||"OTHER";
    if(buf[tn]) buf[tn][nm]=v;
  }
}catch(e){ node.warn("parse: "+e.message); }
return [{payload:buf.AI,topic:"AI"},{payload:buf.AO,topic:"AO"},{payload:buf.AV,topic:"AV"},{payload:buf.BI,topic:"BI"},{payload:buf.BO,topic:"BO"},{payload:buf.BV,topic:"BV"},{payload:buf.MSI,topic:"MSI"},{payload:buf.MO,topic:"MO"},{payload:buf.MSV,topic:"MSV"},{payload:buf.CSV,topic:"CSV"}];

//===== CONFIG =====
const ADDR = "192.168.203.180";
const MAX_R = 3;
const DLY = 1000;
const STUCK_TIMEOUT = 30000;

// tag: 0=NULL 2=UINT 4=REAL 7=STRING 9=ENUM
const WRITES = [
  {nm:"AHU1.SupplyAirTempSetpoint",t:2,i:0,tag:4,v:17.0},
  {nm:"Zone1.TempSetpoint",t:2,i:1,tag:4,v:23.5},
  {nm:"Zone2.TempSetpoint",t:2,i:2,tag:4,v:24.0},
  {nm:"Chiller1.ChWSetpoint",t:2,i:3,tag:4,v:7.0},
  {nm:"Building.DemandLimit",t:2,i:4,tag:4,v:180.0},
  {nm:"System.OccupiedMode",t:5,i:0,tag:9,v:1,pri:8},
  {nm:"AHU1.Enable",t:5,i:1,tag:9,v:1,pri:8},
  {nm:"System.OperatingMode",t:19,i:0,tag:2,v:1,pri:8},
  {nm:"AHU1.FanMode",t:19,i:1,tag:2,v:3,pri:8},
  {nm:"AHU1.SupplyFanSpeed",t:1,i:0,tag:4,v:75.0,pri:8},
  {nm:"AHU1.CoolingValve",t:1,i:1,tag:4,v:60.0,pri:8},
  {nm:"AHU1.SupplyFanCommand",t:4,i:0,tag:9,v:1,pri:8},
  {nm:"Maintenance.Note",t:40,i:3,tag:7,v:"PM scheduled"},
  {nm:"Operator.Message",t:40,i:4,tag:7,v:"Test from NR"},
];
//==================

let s = context.get("s") || null;

// ── START ──
if (msg.payload === "START") {
  if (s && s.ph) {
    const age = Date.now() - (s.ts || 0);
    if (age < STUCK_TIMEOUT) {
      node.warn("กำลังทำงาน — กด inject อีกครั้งเพื่อ force reset");
      s._forceNext = true; context.set("s",s);
      node.status({fill:"yellow",shape:"ring",text:"กดอีกครั้ง = force reset"});
      return null;
    }
    node.warn("Auto-reset (stuck > 30s)");
  }
  if (s && s._forceNext) {
    node.warn("Force reset — เริ่มรอบใหม่");
  }
  s = {rid:Date.now(),ph:"w",addr:ADDR,maxR:MAX_R,dly:DLY,
       att:1,pend:JSON.parse(JSON.stringify(WRITES)),done:[],idx:0,ts:Date.now()};
  context.set("s",s);
  node.status({fill:"blue",shape:"dot",text:`writing ${s.pend.length}...`});
  return emitW(s);
}

if(!s||(msg._rid&&msg._rid!==s.rid)) return null;
s.ts=Date.now(); context.set("s",s);

// ── WRITE RESPONSE ──
if(s.ph==="w") {
  if(s.idx < s.pend.length) {
    const m = mkW(s);
    s.idx++; context.set("s",s);
    node.status({fill:"blue",shape:"ring",text:`[${s.att}] write ${s.idx}/${s.pend.length}`});
    setTimeout(()=>node.send([m,null,null]),s.dly);
    return null;
  }
  s.ph="v"; s.idx=0; context.set("s",s);
  node.status({fill:"yellow",shape:"ring",text:`verifying...`});
  setTimeout(()=>node.send([null,mkV(s),null]),1500);
  return null;
}

// ── VERIFY RESPONSE ──
if(s.ph==="v") {
  const items = (msg.payload&&msg.payload.values) || msg.payload || [];
  const rm={};
  try {
    for(const it of (Array.isArray(items)?items:[])) {
      const k=it.objectId.type+":"+it.objectId.instance;
      try{rm[k]=it.values[0].value[0].value;}catch(e){rm[k]="ERR";}
    }
  } catch(e) { node.warn("verify parse: "+e.message); }

  const ok=[],fail=[];
  for(const w of s.pend){
    const k=w.t+":"+w.i, a=rm[k], e=w.v;
    let m=false;
    if(a!==undefined&&a!=="ERR"){
      if(typeof e==="number"&&typeof a==="number") m=Math.abs(a-e)<0.15;
      else if(typeof e==="string") m=String(a)===e;
      else m=a==e;
    }
    (m?ok:fail).push({...w,actual:a,match:m});
  }
  s.done=s.done.concat(ok);

  if(fail.length===0||s.att>=s.maxR){
    s.done=s.done.concat(fail);
    const r=summ(s); context.set("s",null);
    return [null,null,r];
  }
  node.warn(`Retry ${s.att+1}: ${fail.map(f=>f.nm).join(", ")}`);
  node.status({fill:"yellow",shape:"dot",text:`retry ${s.att+1}: ${fail.length}`});
  s.pend=fail; s.idx=0; s.att++; s.ph="w"; context.set("s",s);
  const m=mkW(s); s.idx++; context.set("s",s);
  setTimeout(()=>node.send([m,null,null]),2000);
  return null;
}
return null;

// ── HELPERS ──
function emitW(st){
  const m=mkW(st); if(!m)return null;
  st.idx++; context.set("s",st);
  return [m,null,null];
}
function mkW(st){
  if(st.idx>=st.pend.length) return null;
  const w=st.pend[st.idx];
  const m = {
    payload: {
      deviceIPAddress: st.addr,
      objectId: { type: w.t, instance: w.i },
      propertyId: 85,
      values: [{ type: w.tag, value: w.v }],
    },
    topic: w.nm, _rid: st.rid
  };
  if (w.pri) m.payload.options = { priority: w.pri };
  return m;
}
function mkV(st){
  return {
    payload: {
      deviceIPAddress: st.addr,
      requestArray: st.pend.map(w=>({objectId:{type:w.t,instance:w.i},properties:[{id:85}]}))
    },
    _rid: st.rid
  };
}
function summ(st){
  const p=st.done.filter(d=>d.match),f=st.done.filter(d=>!d.match),n=st.done.length,ok=f.length===0;
  node.status(ok?{fill:"green",shape:"dot",text:`PASSED ${p.length}/${n} (${st.att} att)`}
                :{fill:"red",shape:"ring",text:`FAIL ${f.length}/${n} (${st.att} att)`});
  return {payload:{status:ok?"ALL PASSED":"HAS FAILURES",total:n,passed:p.length,failed:f.length,
    attempts:st.att,details:st.done.map(d=>({name:d.nm,status:d.match?"PASS":"FAIL",expected:d.v,actual:d.actual}))}};
}

